import React, { useState } from 'react';
import { Button, Text, View } from 'react-native';

const Counter = () => {
  const [count, setCount] = useState(0);
  return (
    <View>
      <Text>Current: {count}</Text>
      <Button title="Add" onPress={() => setCount(count + 1)} />
    </View>
  );
};
